<template>
    <section class="main-content">
        <loader :is-visible="isLoading"></loader>

        
        <div class="padding-t_10 p-0" id="reportstabsdata">
            <div class="left-menu-tab pt-2">
                <div class="col-md-12 p-0 ">
                    <div class="theme-primary partition">
                        <span class="p-name text-white">{{ HeaderTitle }}</span>
                    </div>
                </div>

              <div class="left-tab-container">
                <div class="mt-2 mCustomScrollbar _mCS_4">
                    <a class="card mobile-tab-accordian active" href="javascript:;" data-controllername="billingrule" data-actionname="ImportFormatListing" v-on:click="showMobileTabs = !showMobileTabs;">
                            <div class="card-header" role="tab">                            
                                <h5><span class="mb-0"><i :class="GetSelectedModuleItem.icon"></i> {{ $t(GetSelectedModuleItem.display_name) }}<i
                                            class="fa fa-angle-down rotate-icon float-right" aria-hidden="true"></i></span>
                                </h5> 
                            </div>
                    </a>
                    <div v-if="showMobileTabs"> 
                        <a class="card mobile-tab-accordian" href="javascript:;" v-for="list in TabsList"  v-if="GetSelectedModuleItem.display_name != list.display_name"  :title="list.display_name" v-on:click="SetCurrentTab(list.display_name,list); showMobileTabs = false;">
                            <div role="tab" class="card-header">
                                <h5><span class="mb-0">
                                    <em :class="list.icon"></em>{{ TruncateStr($t(list.display_name),25) }}<em aria-hidden="true" class="fa fa-angle-down rotate-icon float-right"></em>
                                </span>
                                </h5>
                            </div>
                        </a> 
                    </div>
                    <ul class="nav nav-pills flex-column left-tab mt-1 responivecustomtab nav-tabs">                    
                        <li v-for="(item, itemIndex) in TabsList" class="nav-item" v-if="IsSubscriptionBilling || IsUtilityBilling" :key="itemIndex">
                            <a :class="{ 'nav-link left-menu gen_icon': true, 'active show': isActiveTab(item) }" 
                                v-if="item.display_name !== 'AdditionalInfoClient'"
                                :id="item.unique_id" :href="`#${item.extra_condition}`" data-toggle="tab" role="tab"
                                :title="$t(item.display_name)" :aria-controls="item.extra_condition"
                                @click.prevent="setActiveTab(item)">
                                <em class="fa" :class="item.icon" aria-hidden="true"></em>
                                {{ $t(item.display_name) }}
                            </a>
                             <a :class="{ 'nav-link left-menu gen_icon': true, 'active show': isActiveTab(item) }" 
                                v-else-if="item.display_name === 'AdditionalInfoClient'"
                              :id="item.unique_id" :href="`#${item.extra_condition}`" data-toggle="tab" role="tab"
                                :title="$t('TalygenUtility')" :aria-controls="item.extra_condition"
                                @click.prevent="setActiveTab(item)">
                                <em class="fa" :class="item.icon" aria-hidden="true" ></em>
                                {{ $t('TalygenUtility') }}
                            </a>
                        </li>
                        <li class="nav-item" v-else v-show="item.display_name !== 'Plans'">
                        <a :class="{ 'nav-link left-menu gen_icon': true, 'active show': isActiveTab(item) }"
                            :id="item.unique_id" :href="`#${item.extra_condition}`" data-toggle="tab" role="tab"
                            :title="$t(item.display_name)" :aria-controls="item.extra_condition"
                            @click.prevent="setActiveTab(item)">
                            <em class="fa" :class="item.icon" aria-hidden="true"></em>
                            {{ $t(item.display_name) }}
                        </a>
                        </li>
                    </ul>
                </div>                
            </div>
            
            </div>
            <div class="right-content">
                <div id="ReturnRequestHeading" class=" mt-2 theme-primary partition  p-actions-expand"
                    v-if="activeTab != 'aAdditionalNewContacts' && activeTab != 'ancPlanMapping' && activeTab != 'ancInvoices' && activeTab != 'aContracts' && activeTab != 'MeterReading' && activeTab != 'aTax' && activeTab != 'APro' && (activeTab != 'RateSchedule' || (!IsUtilityBilling && activeTab != 'RateSchedule'))">
                   <span class="p-name text-white">{{ HeaderText }}</span>
                    <span class="p-actions float-right">
                        <RouterLink to="/Client/Index" class="p-action-btn text-white float-right">
                            <em class="fa fa-angle-double-left"></em>
                            <br />
                            {{ $t('BacktoList') }}
                        </RouterLink>
                    </span>
                    <span class="p-actions float-right" v-if="activeTab == 'creditInfo'">
                        <a @click="AddMore(activeTab)" class="p-action-btn text-white rqst-doc"><em
                                class="fa fa-plus pr-2"></em> <br />{{ $t('AddMore') }}</a>
                    </span>
                    <span class="p-actions float-right" v-if="activeTab == 'aCompanyHoliday'">
                        <a @click="AddContractHoliady" class="p-action-btn text-white rqst-doc"><em
                                class="fa fa-plus pr-2"></em> <br />{{ $t('Add') }}</a>
                    </span>
                    <span class="p-actions float-right" v-if="activeTab == 'aCompanyHoliday'">
                        <a @click="AddBankHoliady" class="p-action-btn text-white rqst-doc"><em
                                class="fa fa-cogs pr-2"></em> <br />{{ $t('HolidayBank') }}</a>
                    </span>
                    <span class="p-actions float-right" v-if="activeTab == 'aCompanyHoliday' && !isBillingType">
                        <a @click="AddContract" class="p-action-btn text-white rqst-doc"><em
                                class="fa fa-plus pr-2"></em> <br />{{ $t('AddContract') }}</a>
                    </span>
                    <span class="p-actions float-right" v-if="activeTab == 'ancDivisionMapping'">
                        <a @click="AddInvoice" class="p-action-btn text-white rqst-doc"><em
                                class="fa fa-plus pr-2"></em> <br />{{ $t('AddMore') }}</a>
                    </span>
                    <span class="p-actions float-right" v-if="activeTab == 'AdditionalInfo'">
                        <a @click="AddUtility" class="p-action-btn text-white rqst-doc"><em
                                class="fa fa-plus pr-2"></em> <br />{{ $t('AddMore') }}</a>
                    </span>
                </div>

                <div :class="{ 'tab-pane fade p-3 pb-2 border ': true, 'active show': activeTab == 'general' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isGeneral">
                    <!-- <NewClient :ClientData="ClientData"></NewClient> -->
                    <GeneralNewTab :ClientData="ClientData" :UserId="ClientId" IsClient="Client"></GeneralNewTab>
                    <!-- <GeneralSettingmodel :ClientData="ClientData"></GeneralSettingmodel> -->
                    
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'aAddresses' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isAddress">
                    <Address :ClientData="ClientData" :UserId="ClientId" IsClient="Client"></Address>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'clientConfig' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isConfiguration">
                    <ConfigurationModal :ClientId="ClientId"></ConfigurationModal>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'aContactNumbers' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isContact">
                    <ContactNumberVue @userTypeId="receiveUserTypeId" :isEditUser="isEditUser" :UserId="ClientId"
                        IsClient="Client"></ContactNumberVue>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'aAdditionalEmails' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isCommunication">
                    <Communication :GetConfiguration="GetConfiguration" IsClient="Client"></Communication>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'aQuotation' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isQuote">
                    <Quotation :ClientData="ClientData" :UserId="ClientId"></Quotation>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'aContracts' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isContract">
                    <Contract :ClientData="ClientData" :UserId="ClientId"></Contract>
                </div>

                <div :class="{ 'tab-pane fade p-0 pb-2 border-0': true, 'active show': activeTab == 'ancInvoices' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isBill">
                    <BillListing :ClientData="ClientData" :UserId="ClientId"></BillListing>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-2': true, 'active show': activeTab == 'ancPlanMapping' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isPlan">
                    <SubscriptionListing :ClientData="ClientData" :UserId="ClientId"></SubscriptionListing>
                </div>

                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'creditInfo' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isCreditHistory">
                    <CreditHistory :ClientData="ClientData" :UserId="ClientId" :key="refreshKey"></CreditHistory>
                    <AddCreditHistory v-if="AddHistory" :ClientData="ClientData" :UserId="ClientId"></AddCreditHistory>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'aAdditionalNewContacts' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isAdditionalContact">
                    <AdditionalContact :ClientData="ClientData" :UserId="ClientId" :key="refreshKey">
                    </AdditionalContact>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'ancDivisionMapping' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isInvoiceGrouping">
                    <InvoiceGrouping :ClientData="ClientData" :UserId="ClientId" :key="refreshKey"
                        :InvoiceData="InvoiceData" :IsInvoiceGroupingDataShow="IsInvoiceGroupingDataShow">
                    </InvoiceGrouping>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'AdditionalInfo' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isAdditionalInfoClient">
                    <UtilityTab :ClientData="ClientData" :IsAdditionalInfoDataShow="IsAdditionalInfoDataShow"  :AdditionalInfoData="AdditionalInfoData"
                    :UserId="ClientId" :key="refreshKey"></UtilityTab>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'aCompanyHoliday' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isContractHoliday">
                    <ContractHoliday :UserId="ClientId" :key="crefreshKey"></ContractHoliday>
                    <AddContract v-if="IsAddContract" :UserId="ClientId" :IsFor="IsFor"
                        @CloseAddContract="CloseAddContract" :ContractHolidayData="ContractHolidayData"></AddContract>
                    <AddBnakHoliday v-if="IsAddBnakHoliday" @CloseHolidayBank="CloseHolidayBank"></AddBnakHoliday>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'aMeter' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isMeter">
                    <MapMeter :ClientData="ClientData" :UserId="ClientId" :key="refreshKey">
                    </MapMeter>
                </div>

                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'MeterReading' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isMeterReading">
                    <MeterReading :ClientData="ClientData" :UserId="ClientId" :key="refreshKey">
                    </MeterReading>
                </div>


                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-1': true, 'active show': activeTab == 'AdditionalOwner' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isAdditionalOwner">
                    <AdditionalOwner :ClientData="ClientData" :ClientId="ClientId" IsClient="Client">
                    </AdditionalOwner>
                </div>
                

                <!-- Fixed RateSchedule tab - single container with conditional content -->
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'RateSchedule' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="activeTab == 'RateSchedule'">
                    <RateScheduleforUsic 
                        v-if="isBillingType"
                        :ClientData="ClientData" 
                        :ClientId="ClientId" 
                        IsClient="Client">
                    </RateScheduleforUsic>
                    <RateSchedule 
                        v-else
                        :ClientData="ClientData" 
                        :ClientId="ClientId" 
                        IsClient="Client">
                    </RateSchedule>
                </div>
                
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-0': true, 'active show': activeTab == 'aTax' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isTax">
                    <TaxListing :ClientData="ClientData" :ClientId="ClientId" :ChecKPrivilege="isTax"></TaxListing>
                </div>
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-0': true, 'active show': activeTab == 'APro' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="isPro">
                    <Property :ClientData="ClientData" :ClientId="ClientId"  :ChecKPrivilege="isPro"></Property>
                </div>
                 <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-0': true, 'active show': activeTab == 'aWallet' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="aWallet">
                    <WalletRecharge :ClientId="ClientId" :parentId="parentId"></WalletRecharge>
                </div>
               
                <div :class="{ 'tab-pane fade p-0 pb-2 border-0 mt-3': true, 'active show': activeTab == 'aBac' }"
                    :id="activeTab" role="tabpanel" :aria-labelledby="activeTab" v-if="ShowBAC">
                    <BAC :ClientData="ClientData" :UserId="ClientId"></BAC>
                </div>
            </div>
        </div>
    </section>
</template>
<script>
import DataServices from "../../services/DataService";
import GeneralSettingmodel from "../Client/ClientDetails/GeneralSettingModal.vue"
import Address from "../../views/Users/Address.vue";
import ConfigurationModal from '../Client/ClientDetails/ConfigurationData.vue';
import ContactNumberVue from '../../components/Modals/ContactNumber.vue';
import Communication from "../../views/Users/Communication.vue";
import Quotation from "../Client/ClientDetails/Quotation.vue"
import Contract from "../Client/ClientDetails/ContractTabList.vue"
import CreditHistory from "../Client/ClientDetails/CreditHistory.vue"
import AddCreditHistory from "../Client/ClientDetails/AddCreditHistory.vue"
import AdditionalContact from "../Client/ClientDetails/AdditionalContact.vue"
import SubscriptionListing from "./ClientDetails/SubscriptionListing.vue";
import BillListing from "./ClientDetails/BillListing.vue";
import ContractHoliday from '../Client/ClientDetails/ContractHoliday.vue'
import AddContract from './ClientDetails/AddContractHoliday.vue'
import InvoiceGrouping from "./ClientDetails/InvoiceGrouping.vue"
import AddBnakHoliday from "./ClientDetails/AddBnakHoliday.vue";
import MapMeter from "../Client/ClientDetails/MapMeter.vue"
import AdditionalOwner from "../Client/ClientDetails/AdditionalOwner.vue"
import RateSchedule from "../Client/ClientDetails/RateSchedule.vue"
import RateScheduleforUsic from "../Client/ClientDetails/RateScheduleforUsic.vue"
import MeterReading from "../Client/ClientDetails/MeterReading.vue"
import TaxListing from "./ClientDetails/TaxListing.vue";
import UtilityTab from "./ClientDetails/UtilityTab.vue";
import Property from "./ClientDetails/Property.vue";
import NewClient from "./NewClient.vue";
import GeneralNewTab from "./ClientDetails/GeneralNewTab.vue";
import WalletRecharge from "./Wallet/WalletRecharge.vue";
import BAC from "../Client/ClientDetails/BACTabList.vue"
export default {
    components: {
        GeneralSettingmodel, Address, ConfigurationModal, ContactNumberVue, Communication, Quotation, Contract,
        CreditHistory, AddCreditHistory, AdditionalContact, SubscriptionListing, BillListing, InvoiceGrouping, ContractHoliday, AddContract,
         AddBnakHoliday, MapMeter, MeterReading, AdditionalOwner, RateSchedule,TaxListing,UtilityTab,Property,NewClient,GeneralNewTab,WalletRecharge,RateScheduleforUsic,BAC
    },
    
    data() {
        return {
            isLoading: false,
            isGeneral: false,
            isAddress: false,
            isConfiguration: false,
            isBill: false,
            isMeter: false,
            isTax:false,
            isPro:false,
            isMeterReading: false,
            isContact: false,
            isQuote: false,
            isContract: false,
            isPlan: false,
            isPlanSelection: false,
            isPlanDetails: false,
            isCreditHistory: false,
            isInvoiceGrouping: false,
            isAdditionalContact: false,
            activeTab: 'general',
            MandatoryString: this.$t('MandatoryString'),
            companyId: null,
            userId: null,
            TabsList: [],
            ClientData: [],
            HeaderText: this.$t('GeneralDetails'),
            HeaderTitle: '',
            GeneralSettingModal: false,
            AdditionalContact: false,
            ShowAddress: false,
            ShowConfiguration: false,
            ShowCommunication: false,
            ShowContactNumbers: false,
            ShowContract: false,
            ShowCreditHistory: false,
            ShowQuotation: false,
            ShowMeter: false,
            ShowMeterReading: false,
            ClientId: 0,
            isEditUser: '',
            Headerstext: '',
            isCommunication: '',
            GetConfiguration: {},
            planDetails: [],
            AddHistory: false,
            refreshKey: 0,
            InvoiceData: [],
            IsAddContract: false,
            isContractHoliday: false,
            ContractHolidayData: null,
            IsAddBnakHoliday: false,
            IsInvoiceGroupingDataShow: false,
            IsAdditionalInfoDataShow: false,
            crefreshKey: 0,
            isAdditionalOwner: false,
            ShowAdditionalOwner: false,
            isRateSchedule: false,
            ShowRateSchedule: false,
            IsSubscriptionBilling : false,
            IsUtilityBilling : false,
            isAdditionalInfoClient:false,
            showMobileTabs: false,
            AdditionalInfoData:[],
            currentTab:"GeneralDetails",
            aWallet: false,
            isUpdatingHash: false, // Flag to prevent hashchange handler from running during programmatic updates
            isBillingType:false,
            ShowBAC: false,
           
        }
    },
    created: async function () {
        var vm = this;
       // debugger
        vm.userId = vm.GetUserInfo.ID;
        this.isBillingType = localStorage.getItem("billingType") === "USIC";
        vm.user_type = vm.GetUserInfo.UserType;
        vm.companyId = vm.GetUserInfo.CompanyId;
        await  this.CheckExtraFeatures();
        await this.GetTabsContent();
        await this.GetClientDetailByClientId(vm.$route.params.id);
        
        // Check for hash in URL first (after tabs are loaded)
        const hash = window.location.hash.replace('#', '');
        if (hash) {
            // Find tab by hash (supports display_name hash format)
            const tabFromHash = vm.findTabByHash(hash);
            if (tabFromHash) {
                await this.setActiveTab(tabFromHash);
            } else {
                // Handle special cases
                if (hash === 'general' || hash === 'aContracts' || hash === 'aWallet' ||  hash === 'aBAC') {
                    await this.setActiveTab(hash);
                } else {
                    // Hash doesn't match any tab, use default logic
                    if (this.$route.query && this.$route.query.redirectFrom == 'Contract') {
                        await this.setActiveTab('aContracts');
                    } 
                    else if (this.$route.query && this.$route.query.redirectFrom == 'BAC') {
                        await this.setActiveTab('aBac');
                    }
                    else if(this.$route.query && this.$route.query.redirectFrom == 'Wallet') {
                        await this.setActiveTab('aWallet');
                    } else {
                        await this.setActiveTab('general');
                    }
                }
            }
        } else {
            // No hash, use default logic
            if (this.$route.query && this.$route.query.redirectFrom == 'Contract') {
                await this.setActiveTab('aContracts');
            }
             else if (this.$route.query && this.$route.query.redirectFrom == 'BAC') {
                await this.setActiveTab('aBac');
            }
             else if(this.$route.query && this.$route.query.redirectFrom == 'Wallet') {
                await this.setActiveTab('aWallet');
            } else {
                await this.setActiveTab('general');
            }
        }
        vm.isEditUser = "EditUser";
        vm.GetUserDetailByUserId();
        
        // Listen for hash changes
        window.addEventListener('hashchange', vm.handleHashChange);
    },
    beforeDestroy() {
        // Clean up event listener
        window.removeEventListener('hashchange', this.handleHashChange);
    },
    computed: {
        GetSelectedModuleItem() {            
            var ths = this;
            var getModuleObj = ths.TabsList.filter((x) => {
                return x.display_name == ths.currentTab;
            });    
            return getModuleObj.length > 0 ? getModuleObj[0] : { icon: '', display_name: '' };
        },
        // Optional: Computed property for RateSchedule component
        rateScheduleComponent() {
            return this.isBillingType ? 'RateScheduleforUsic' : 'RateSchedule';
        }
    },
    methods: {
        // Convert display_name to URL-friendly hash (e.g., "GeneralDetails" -> "general-details", "General Details" -> "general-details")
        getTabHashFromDisplayName(displayName) {
            if (!displayName) return '';
            // First handle camelCase by adding hyphens before capital letters
            let result = displayName.replace(/([a-z])([A-Z])/g, '$1-$2');
            // Convert to lowercase
            result = result.toLowerCase();
            // Replace spaces with hyphens
            result = result.replace(/\s+/g, '-');
            // Replace multiple hyphens with single hyphen
            result = result.replace(/-+/g, '-');
            // Remove leading and trailing hyphens
            result = result.replace(/^-+|-+$/g, '');
            return result;
        },
        // Find tab by hash (supports both display_name hash and technical identifiers)
        findTabByHash(hash) {
            var vm = this;
            // First try to find by display_name converted to hash
            const tabByDisplayName = vm.TabsList.find(tab => {
                const tabHash = vm.getTabHashFromDisplayName(tab.display_name);
                return tabHash === hash;
            });
            if (tabByDisplayName) return tabByDisplayName;
            
            // Fallback to technical identifiers
            return vm.TabsList.find(tab => 
                tab.extra_condition === hash || tab.unique_id === hash
            );
        },
        handleHashChange() {
            var vm = this;
            // Don't handle hash change if we're the ones updating it programmatically
            if (vm.isUpdatingHash) {
                return;
            }
            const hash = window.location.hash.replace('#', '');
            if (hash) {
                // Find tab by hash (supports display_name hash format)
                const tabFromHash = vm.findTabByHash(hash);
                if (tabFromHash) {
                    // Prevent hash update in setActiveTab since hash is already correct
                    vm.isUpdatingHash = true;
                    vm.setActiveTab(tabFromHash);
                    setTimeout(() => {
                        vm.isUpdatingHash = false;
                    }, 0);
                } else if (hash === 'general' || hash === 'aContracts' || hash === 'aWallet') {
                    vm.isUpdatingHash = true;
                    vm.setActiveTab(hash);
                    setTimeout(() => {
                        vm.isUpdatingHash = false;
                    }, 0);
                }
            }
        },
       /*Start Code Check SUBSCRIPTION_BILLING Plan  Rakesh Thakur Dated:15-May-2025*/ 
        async CheckExtraFeatures(type) {
            var vm =this;
            const params = `featureCode=GET_EXTRA_FEATURE_BILLING&outputType=list`;
            try {
                const response = await DataServices.CheckExtraFeatures(params);
                if (response.data) {
                    const features = JSON.parse(response.data);
                    features.forEach(feature => {
                        if (feature.FEATURE_CODE === 'SUBSCRIPTION_BILLING') {
                            vm.IsSubscriptionBilling = true;
                        }
                        if(feature.FEATURE_CODE === 'UTILITY_BILLING' ){
                            vm.IsUtilityBilling = true;
                        }
                    });
                }
            } catch (error) {
                
                  console.log("Error checking extra features:", error);
            }
        },
         /*End Code Check SUBSCRIPTION_BILLING Plan  Rakesh Thakur Dated:15-May-2025*/
         
        GetClientDetailByClientId: async function (val) {
            var vm = this;
            var params = `ClientId=${val}`;
            await DataServices.GetClientDetailByClientId(params).then(function (response) {                
                vm.ClientData = response.data;
                vm.ClientId = vm.ClientData.clientdetail.user_id;
                vm.HeaderTitle = response.data.clientdetail.first_name + ' ' + response.data.clientdetail.last_name;
            });
        },
        receiveUserTypeId(userTypeid, userName) {
            var vm = this;
            vm.userType = '';
            vm.userType = parseInt(userTypeid);
            vm.Headerstext = userName;
        },
        async GetUserDetailByUserId() {
            var vm = this
            try {
                let url = `userId=${vm.$route.params.id}`;
                await DataServices.GetUserDetailById(url).then(response => {
                    if (response.data) {
                        vm.userType = response.data.UserType;
                        vm.UserTypeName = response.data.USER_TYPE_NAME;
                        vm.userDetail = response.data;
                        let userName = response.data.User_Name.replace(" ", '') + ' ';
                        let designation = response.data.designation + '  , ' || ' ';
                        let department = response.data.department + ' ' || ' ';
                        vm.IS_DEFAULT = response.data.IS_DEFAULT;
                        vm.Headerstext = `${userName}-${designation}${department}`;
                    }
                })
            } catch (error) {
                console.log("error message", error);
            }
        },
        AddMore(item) {
            var vm = this;
            if (item == 'creditInfo') {
                vm.AddHistory = !vm.AddHistory;
            }
        },
        SetCurrentTab: function(moduleName,itm) { 
            this.currentTab = moduleName;  
            this.setActiveTab(itm);
        },
        updateUrlHash(tabIdentifier) {
            // Only update if hash is different to avoid unnecessary updates
            const currentHash = window.location.hash.replace('#', '');
            if (currentHash !== tabIdentifier) {
                // Set flag to prevent hashchange handler from running
                this.isUpdatingHash = true;
                // Update URL hash
                window.location.hash = tabIdentifier;
                // Reset flag after a short delay to allow hashchange event to process
                setTimeout(() => {
                    this.isUpdatingHash = false;
                }, 0);
            }
        },
        tabStateMap() {
            return {
                general: 'isGeneral',
                aAddresses: 'isAddress',
                clientConfig: 'isConfiguration',
                aContactNumbers: 'isContact',
                aAdditionalEmails: 'isCommunication',
                aQuotation: 'isQuote',
                aContracts: 'isContract',
                ancPlanMapping: 'isPlan',
                ancInvoices: 'isBill',
                creditInfo: 'isCreditHistory',
                aAdditionalNewContacts: 'isAdditionalContact',
                ancDivisionMapping: 'isInvoiceGrouping',
                AdditionalInfo: 'isAdditionalInfoClient',
                aCompanyHoliday: 'isContractHoliday',
                aMeter: 'isMeter',
                MeterReading: 'isMeterReading',
                AdditionalOwner: 'isAdditionalOwner',
                RateSchedule: 'isRateSchedule',
                aTax: 'isTax',
                APro: 'isPro',
                aWallet: 'aWallet',
                aBac: 'ShowBAC',
            };
        },
        resetAllTabs() {
            Object.values(this.tabStateMap()).forEach(key => {
                this[key] = false;
            });
        },

        setActiveTab(item) {
            const vm = this;

            const tabKey =
                typeof item === 'string'
                ? item
                : item.unique_id || item.extra_condition;

            // Sync URL hash
            if (!vm.isUpdatingHash && tabKey) {
                vm.updateUrlHash(tabKey);
            }

            // Reset all tab flags
            vm.resetAllTabs();

            // Set active tab
            vm.activeTab = tabKey;

            // Enable correct tab
            const stateKey = vm.tabStateMap()[tabKey];
            if (stateKey) {
                vm[stateKey] = true;
            }

            // Header
            if (item?.display_name) {
                vm.HeaderText = vm.$t(item.display_name);
            }

            // Call tab-specific loaders
            vm.openTabAction(tabKey);
        },

        openTabAction(tabKey) {
            debugger;
            switch (tabKey) {
                case 'general':
                this.openGeneralSettingDetail();
                break;

                case 'aContracts':
                this.openContract();
                break;

                case 'aAddresses':
                this.openAddress();
                break;

                case 'clientConfig':
                this.openConfiguration();
                break;

                case 'aContactNumbers':
                this.openContactNumbers();
                break;

                case 'aQuotation':
                this.openQuotation();
                break;

                case 'creditInfo':
                this.openCreditHistory();
                break;

                case 'aMeter':
                this.openMeter();
                break;

                case 'MeterReading':
                this.openMeterReading();
                break;

                // privilege-based tabs
                case 'AdditionalInfo':
                this.LoadAdditionalInfo();
                //this.checkAdditionalInfoPrivilege();
                break;

                case 'aTax':
                this.checkTaxPrivilege();
                break;

                case 'APro':
                this.checkPropertyPrivilege();
                break;
                case 'ancDivisionMapping':
                this.GetInvoicedata();
                break;
                case 'aBac':
                this.openBAC();
                break;

                
            }
        },

        LoadAdditionalInfo : async function () {
            var vm = this;
            vm.AdditionalInfoData=[];
            var url = `ClientId=${vm.ClientId}`
            await DataServices.GetAdditionalInformation(url).then((response) => {
                if (response.data.length > 0) {
                    vm.AdditionalInfoData = response.data;
                    vm.IsAdditionalInfoDataShow = false;
                }
                else {
                    vm.IsAdditionalInfoDataShow = true;
                }
            });
        },
        GetInvoicedata: function () {
            debugger;
            var vm = this;
            vm.InvoiceData =[];
            var url = `Serach=&ClientId=${vm.ClientId}&SortBy=&SortExp=&PageSize=10&PageNumber=1`
            DataServices.GetInvoiceData(url).then((response) => {

                if (response && response.data.result.Data.length > 0) {
                    vm.InvoiceData = response.data.result.Data;
                    vm.IsInvoiceGroupingDataShow = false;
                }
                else {
                    vm.IsInvoiceGroupingDataShow = true;
                }
            });
        },
       
        openGeneralSettingDetail: function () {
            var vm = this;
            vm.GeneralSettingModal = !vm.GeneralSettingModal;
        },
        openAdditionalContact: function () {
            var vm = this;
            vm.AdditionalContact = !vm.AdditionalContact;
